let handler;

export function initialize(element, dotNetRef) {
    handler = new DropZoneHandler(element, dotNetRef);
    handler.start();
}

export function dispose() {
    handler?.dispose();
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone-prompt {
    color: #6c757d;
    font-size: 1.1rem;
    margin: 0;
    pointer-events: none;
}

::deep .drop-zone--highlight {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-error {
    color: #dc3545;
}

.file-details {
    color: #212529;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    font-size: 0.85rem;
    margin-left: 1rem;
    flex-shrink: 0;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}
